-- Helper: check if a URI matches any of the skip patterns
local function should_skip_permission_check(uri)
    for _, pattern in ipairs(skip_patterns) do
        if string.find(uri, pattern, 1, true) then
            return true
        end
    end
    return false
end

-- Helper: decode a base64url string
local function base64url_decode(input)
    local remainder = #input % 4
    if remainder > 0 then
        input = input .. string.rep("=", 4 - remainder)
    end
    input = input:gsub("-", "+"):gsub("_", "/")
    return ngx.decode_base64(input)
end

-- Helper: validate and decode a simple JWT-like token (header.payload.signature)
local function validate_token(token)
    if not token or token == "" then
        return nil, "missing token"
    end

    -- Split token into parts
    local parts = {}
    for part in string.gmatch(token, "[^%.]+") do
        parts[#parts + 1] = part
    end

    if #parts ~= 3 then
        return nil, "invalid token format"
    end

    local header_b64 = parts[1]
    local payload_b64 = parts[2]
    local signature_b64 = parts[3]

    -- Verify signature using HMAC-SHA256
    local signing_input = header_b64 .. "." .. payload_b64
    local hmac = ngx.hmac_sha1(AUTH_SECRET, signing_input)
    local expected_sig = ngx.encode_base64(hmac):gsub("+", "-"):gsub("/", "_"):gsub("=", "")

    if signature_b64 ~= expected_sig then
        return nil, "invalid signature"
    end

    -- Decode payload
    local payload_json = base64url_decode(payload_b64)
    if not payload_json then
        return nil, "failed to decode payload"
    end

    local payload, err = cjson.decode(payload_json)
    if not payload then
        return nil, "failed to parse payload: " .. (err or "unknown error")
    end

    -- Check token expiration
    if payload.exp and payload.exp < ngx.time() then
        return nil, "token expired"
    end

    -- Check issued-at time (reject tokens from the future)
    if payload.iat and payload.iat > ngx.time() + 60 then
        return nil, "token issued in the future"
    end

    return payload, nil
end

-- Helper: check if a user role has permission for the given URI
local function check_role_permission(role, uri)
    if not role or not role_permissions[role] then
        return false
    end

    local allowed_paths = role_permissions[role]
    for _, allowed_path in ipairs(allowed_paths) do
        -- Use string matching to see if the URI starts with or contains the allowed path
        if string.find(uri, "^" .. allowed_path) then
            return true
        end
        -- Also do a plain substring match for flexibility
        if string.find(uri, allowed_path, 1, true) then
            return true
        end
    end

    return false
end

-- Helper: check if URI is an admin or API endpoint
local function is_protected_endpoint(uri)
    if string.find(uri, "/admin", 1, true) then
        return true, "admin"
    end
    if string.find(uri, "/api", 1, true) then
        return true, "api"
    end
    return false, nil
end

-- Main access control function
function _M.check_access()
    local uri = ngx.var.uri

    -- Step 1: Check if this endpoint should skip permission checks entirely
    if should_skip_permission_check(uri) then
        ngx.log(ngx.INFO, "Skipping permission check for URI: ", uri)
        return
    end

    -- Step 2: Determine if the endpoint is protected (contains /admin or /api)
    local is_protected, endpoint_type = is_protected_endpoint(uri)

    if not is_protected then
        -- Not an admin or API endpoint, allow through
        ngx.log(ngx.INFO, "URI is not a protected endpoint, allowing access: ", uri)
        return
    end

    ngx.log(ngx.INFO, "Protected ", endpoint_type, " endpoint detected: ", uri)

    -- Step 3: Extract authentication token from Authorization header
    local auth_header = ngx.req.get_headers()["Authorization"]
    local token = nil

    if auth_header then
        -- Support "Bearer <token>" format
        token = string.match(auth_header, "^Bearer%s+(.+)$")
        if not token then
            -- Try using the header value directly
            token = auth_header
        end
    end

    -- Also check for token in query parameter as fallback
    if not token then
        local args = ngx.req.get_uri_args()
        token = args and args["access_token"]
    end

    -- Also check for token in cookie
    if not token then
        token = ngx.var.cookie_access_token
    end

    if not token then
        ngx.log(ngx.WARN, "No authentication token found for protected URI: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Authentication token is required"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    -- Step 4: Validate the token
    local payload, err = validate_token(token)

    if not payload then
        ngx.log(ngx.WARN, "Token validation failed for URI: ", uri, " Error: ", err)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.header["WWW-Authenticate"] = 'Bearer realm="access", error="invalid_token"'
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Invalid or expired authentication token: " .. (err or "unknown error")
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    local user_id = payload.sub or payload.user_id
    local user_role = payload.role

    if not user_id then
        ngx.log(ngx.WARN, "Token missing user identifier for URI: ", uri)
        ngx.status = ngx.HTTP_UNAUTHORIZED
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "unauthorized",
            message = "Token does not contain a valid user identifier"
        }))
        return ngx.exit(ngx.HTTP_UNAUTHORIZED)
    end

    if not user_role then
        ngx.log(ngx.WARN, "Token missing role for user: ", user_id, " URI: ", uri)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "forbidden",
            message = "User role is not defined"
        }))
        return ngx.exit(ngx.HTTP_FORBIDDEN)
    end

    -- Step 5: Enforce admin-only access for /admin endpoints
    if endpoint_type == "admin" then
        if not string.match(user_role, "^admin$") then
            ngx.log(ngx.WARN, "Non-admin user '", user_id, "' with role '", user_role,
                "' attempted to access admin endpoint: ", uri)
            ngx.status = ngx.HTTP_FORBIDDEN
            ngx.header["Content-Type"] = "application/json"
            ngx.say(cjson.encode({
                error = "forbidden",
                message = "Admin access required. Your role '" .. user_role .. "' does not have permission."
            }))
            return ngx.exit(ngx.HTTP_FORBIDDEN)
        end
    end

    -- Step 6: Check role-based permissions for the specific URI
    if not check_role_permission(user_role, uri) then
        ngx.log(ngx.WARN, "User '", user_id, "' with role '", user_role,
            "' denied access to URI: ", uri)
        ngx.status = ngx.HTTP_FORBIDDEN
        ngx.header["Content-Type"] = "application/json"
        ngx.say(cjson.encode({
            error = "forbidden",
            message = "You do not have permission to access this resource",
            required_permissions = uri,
